mapper.select:
SELECT

FROM USER_ACCOUNT
WHERE ACCOUNT_ID = #{accountId,jdbcType=NUMERIC}
  AND USER_NUM = #{userNum,jdbcType=NUMERIC}

SELECT COUNT(*)
FROM USER_ACCOUNT
WHERE USER_NUM = #{userNum,jdbcType=NUMERIC}
  AND BANK_NAME = #{bankName,jdbcType=NVARCHAR}
  AND ACCOUNT_NUM = #{accountNum,jdbcType=VARCHAR}

  AND ACCOUNT_ID != #{accountId,jdbcType=NUMERIC}

mapper.delete:
DELETE FROM USER_ACCOUNT
WHERE ACCOUNT_ID = #{accountId,jdbcType=NUMERIC}
  AND USER_NUM = #{userNum,jdbcType=NUMERIC}
  AND BALANCE = 0

mapper.update:
UPDATE USER_ACCOUNT
SET
    BALANCE = BALANCE + #{amount,jdbcType=NUMERIC},
    UPDATE_DT = SYSDATE
WHERE ACCOUNT_ID = #{accountId,jdbcType=NUMERIC}
  AND USER_NUM = #{userNum,jdbcType=NUMERIC}

UPDATE USER_ACCOUNT
SET
    BALANCE = BALANCE - #{amount,jdbcType=NUMERIC},
    UPDATE_DT = SYSDATE
WHERE ACCOUNT_ID = #{accountId,jdbcType=NUMERIC}
  AND USER_NUM = #{userNum,jdbcType=NUMERIC}
  AND BALANCE >= #{amount,jdbcType=NUMERIC}

mapper.select:
SELECT NVL(SUM(BALANCE), 0)
FROM USER_ACCOUNT
WHERE USER_NUM = #{userNum,jdbcType=NUMERIC}
